import{_ as t,o as d,c as a,e}from"./app-4cb4de65.js";const r={},h=e('<h1 id="即兴沟通" tabindex="-1"><a class="header-anchor" href="#即兴沟通" aria-hidden="true">#</a> 即兴沟通</h1><h2 id="保持冷静-驯服焦虑这头猛兽" tabindex="-1"><a class="header-anchor" href="#保持冷静-驯服焦虑这头猛兽" aria-hidden="true">#</a> 保持冷静：驯服焦虑这头猛兽</h2><p>管控自己的焦虑情绪 发言焦虑症状 ABC</p><ul><li>情感症状 Affective Symptoms</li><li>行为症状 Behavioral Symptoms</li><li>认知症状 Cognitive Symptoms</li></ul><p>正念至关重要 关注并承认那些不愉快的感受，不要忽视否认它们，也不要因此自责。当你正在体验这些感受时，一定要相信它们并不能定义你这个人。 在感受到焦虑等负面情绪时，不妨提醒自己，你和你的情绪是两回事。把自己想象成其他人，再去观察自己正在经历的情绪。 将焦虑重新定义为让你兴奋的事，告诉自己“我很兴奋”，将演讲视为一次机会而非一项严酷的挑战。</p><p>吸气时数三声，呼气时数六声。</p><p>我有自己独特的价值；我可以做到；我是谁不重要，我所说的内容引人入胜。</p><p>“聚光灯效应”：人们常常会因为自己的焦虑情绪和自己会给他人留下的印象而不断内耗，去往往忽略了关注自己。</p><h3 id="应对焦虑症状-abc-的技巧" tabindex="-1"><a class="header-anchor" href="#应对焦虑症状-abc-的技巧" aria-hidden="true">#</a> 应对焦虑症状 ABC 的技巧</h3><table><thead><tr><th>技巧</th><th>描述</th><th>说明</th></tr></thead><tbody><tr><td>训练正念</td><td>承认并接纳自己的感受</td><td>这些感受是完全合理且正常的</td></tr><tr><td>呼吸</td><td>深呼吸，当你有意识地呼吸时，让气息填满你的小腹</td><td>深呼吸或瑜伽式呼吸有助于驱散焦虑；呼吸时长应为吸气时长的两倍</td></tr><tr><td>放慢动作</td><td>放慢手势和其他动作</td><td>言语需要与肢体动作保持同步；让所有动作慢下来，保持冷静</td></tr><tr><td>给身体降温</td><td>手握一瓶凉水或其他冷的东西</td><td>通过给自己降温的方式减少脸红和出汗现象</td></tr><tr><td>分泌唾液</td><td>咀嚼口香糖或含片</td><td>咀嚼有助于激活唾液腺</td></tr><tr><td>积极的自我暗示</td><td>在心中默念积极“咒语”</td><td>此举有助于平息你内心的批判声音，积极地改变你的想法</td></tr><tr><td>回到话题，以提问推进</td><td>重复你说过的话，提出问题</td><td>避免过于频繁地重复，但要唤起你的记忆，重复你刚刚说过的话，或者向听众提出一些问题</td></tr><tr><td>理性一点</td><td>告诉自己，如果搞砸了，“最坏”的结果是什么（提示：即使是糟糕的情况，其实也没有那么糟糕）</td><td>人们的绝大部分注意力都集中在自己身上，而不在你身上，记住这一点，理性就会占上风</td></tr><tr><td>通过吸气减少填充词</td><td>确保每个词都掷地有声，这样你就需要吸气了</td><td>你会发现所有填充词（“比如说”“好吧”）都会消失</td></tr></tbody></table><h2 id="释放潜能" tabindex="-1"><a class="header-anchor" href="#释放潜能" aria-hidden="true">#</a> 释放潜能</h2><p>避免完美主义碍手碍脚</p><h2 id="重新定义" tabindex="-1"><a class="header-anchor" href="#重新定义" aria-hidden="true">#</a> 重新定义</h2><p>杜绝封闭式或抗拒式思维</p><h2 id="学会倾听" tabindex="-1"><a class="header-anchor" href="#学会倾听" aria-hidden="true">#</a> 学会倾听</h2><p>了解他们当下真正的需求</p><h2 id="组织安排" tabindex="-1"><a class="header-anchor" href="#组织安排" aria-hidden="true">#</a> 组织安排</h2><p>迅速地组织安排你的即兴发言内容</p><h2 id="聚焦重点" tabindex="-1"><a class="header-anchor" href="#聚焦重点" aria-hidden="true">#</a> 聚焦重点</h2><p>提炼你的想法，使其重点突出、引人入胜</p>',20),i=[h];function n(c,s){return d(),a("div",null,i)}const l=t(r,[["render",n],["__file","即兴沟通.html.vue"]]);export{l as default};
